import requests

# Define the Kong admin endpoint URL
admin_url = "http://localhost:8001"

# Define the services, routes, and upstream targets to be configured
services = [
    {
        "name": "service-1",
        "url": "http://example.com"
    },
    {
        "name": "service-2",
        "url": "http://example.net"
    }
]
routes = [
    {
        "paths": ["/path-1"],
        "methods": ["GET"],
        "strip_path": True,
        "preserve_host": False
    },
    {
        "paths": ["/path-2"],
        "methods": ["POST"],
        "strip_path": False,
        "preserve_host": True
    }
]
upstreams = [
    {
        "name": "upstream-1",
        "targets": [
            {
                "url": "http://example.com:80"
            },
            {
                "url": "http://example.net:80"
            }
        ]
    },
    {
        "name": "upstream-2",
        "targets": [
            {
                "url": "http://example.com:443"
            },
            {
                "url": "http://example.net:443"
            }
        ]
    }
]

# POST the configuration to Kong's admin endpoint
for service in services:
    requests.post(f"{admin_url}/services", json=service)

for route in routes:
    requests.post(f"{admin_url}/routes", json=route)

for upstream in upstreams:
    requests.post(f"{admin_url}/upstreams", json=upstream)